import SpeakBtn from "./SpeakBtn";

const ExampleItem = ({ ex }) => {
  return (
    <div className="border border-white/10 rounded-lg px-3 py-1 text-sm">
      <div className="flex items-center justify-between">
        <p className="text-gray-200 text-sm sm:text-base">{ex?.en}</p>
        <SpeakBtn text={ex?.en} />
      </div>
      <p className="text-gray-400 text-xs sm:text-sm mt-1">{ex?.bn}</p>
    </div>
  );
};

export default ExampleItem;
